import React from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft } from 'lucide-react';

export default function Mentorship() {
  const navigate = useNavigate();

  return (
    <div className="min-h-screen bg-gray-50 p-4">
      <button onClick={() => navigate('/dashboard')} className="flex items-center gap-2 text-blue-600 mb-8">
        <ArrowLeft className="w-5 h-5" /> Back
      </button>
      <div className="max-w-4xl mx-auto">
        <h1 className="text-3xl font-bold text-gray-900 mb-8">Mentorship Program</h1>
        <div className="bg-white rounded-lg shadow p-6">
          <p className="text-gray-600">Connect with experienced alumni mentors to guide your career path.</p>
        </div>
      </div>
    </div>
  );
}
